# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

import hmac
import hashlib
import struct
import time
import base64
import os
import json
import qrcode
from io import BytesIO


class TOTPAuthenticator:
    """Time-based One-Time Password (TOTP) two-factor authentication system."""

    def __init__(self, issuer="MyApp", digits=6, period=30, algorithm="SHA1",
                 storage_file="totp_users.json"):
        self.issuer = issuer
        self.digits = digits
        self.period = period
        self.algorithm = algorithm
        self.storage_file = storage_file
        self.users = self._load_users()

    def _load_users(self):
        """Load user data from storage file."""
        try:
            with open(self.storage_file, "r") as f:
                return json.load(f)
        except (FileNotFoundError, json.JSONDecodeError):
            return {}

    def _save_users(self):
        """Save user data to storage file."""
        with open(self.storage_file, "w") as f:
            json.dump(self.users, f, indent=2)

    def generate_secret(self, length=20):
        """Generate a random secret key for TOTP."""
        random_bytes = os.urandom(length)
        secret = base64.b32encode(random_bytes).decode("utf-8").rstrip("=")
        return secret

    def _decode_secret(self, secret):
        """Decode a base32-encoded secret, adding padding if necessary."""
        secret = secret.upper().replace(" ", "")
        # Add padding
        padding = 8 - (len(secret) % 8)
        if padding != 8:
            secret += "=" * padding
        return base64.b32decode(secret)

    def _get_hash_algorithm(self):
        """Get the hash algorithm function."""
        algorithms = {
            "SHA1": hashlib.sha1,
            "SHA256": hashlib.sha256,
            "SHA512": hashlib.sha512,
        }
        return algorithms.get(self.algorithm.upper(), hashlib.sha1)

    def _generate_hotp(self, secret_bytes, counter):
        """Generate HOTP value for a given secret and counter."""
        # Convert counter to 8-byte big-endian
        counter_bytes = struct.pack(">Q", counter)

        # Compute HMAC
        hash_algo = self._get_hash_algorithm()
        hmac_digest = hmac.new(secret_bytes, counter_bytes, hash_algo).digest()

        # Dynamic truncation
        offset = hmac_digest[-1] & 0x0F
        truncated = struct.unpack(">I", hmac_digest[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF

        # Generate OTP
        otp = truncated % (10 ** self.digits)
        return str(otp).zfill(self.digits)

    def generate_totp(self, secret, timestamp=None):
        """Generate a TOTP code for the given secret and current time."""
        if timestamp is None:
            timestamp = time.time()

        counter = int(timestamp) // self.period
        secret_bytes = self._decode_secret(secret)
        return self._generate_hotp(secret_bytes, counter)

    def verify_totp(self, secret, code, timestamp=None, window=1):
        """
        Verify a TOTP code against the secret.

        Args:
            secret: The shared secret key
            code: The TOTP code to verify
            timestamp: Optional timestamp (defaults to current time)
            window: Number of time steps to check before and after current
                    (default=1 allows for 30s clock drift in each direction)

        Returns:
            True if the code is valid, False otherwise
        """
        if timestamp is None:
            timestamp = time.time()

        code = str(code).zfill(self.digits)

        for offset in range(-window, window + 1):
            check_timestamp = timestamp + (offset * self.period)
            expected_code = self.generate_totp(secret, check_timestamp)
            if hmac.compare_digest(code, expected_code):
                return True

        return False

    def get_provisioning_uri(self, username, secret):
        """
        Generate the otpauth:// URI for provisioning authenticator apps.
        """
        issuer_encoded = self.issuer.replace(" ", "%20")
        username_encoded = username.replace(" ", "%20")

        uri = (
            f"otpauth://totp/{issuer_encoded}:{username_encoded}"
            f"?secret={secret}"
            f"&issuer={issuer_encoded}"
            f"&algorithm={self.algorithm}"
            f"&digits={self.digits}"
            f"&period={self.period}"
        )
        return uri

    def generate_qr_code(self, username, secret, filepath=None):
        """
        Generate a QR code image for the TOTP provisioning URI.

        Args:
            username: The username/account name
            secret: The TOTP secret
            filepath: Optional file path to save the QR code image

        Returns:
            BytesIO object containing the QR code PNG image
        """
        uri = self.get_provisioning_uri(username, secret)

        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")

        # Save to file if filepath provided
        if filepath:
            img.save(filepath)
            print(f"QR code saved to: {filepath}")

        # Also return as BytesIO
        buffer = BytesIO()
        img.save(buffer, format="PNG")
        buffer.seek(0)
        return buffer

    def register_user(self, username, email=None):
        """
        Register a new user for TOTP 2FA.

        Returns:
            dict with secret, provisioning URI, and QR code path
        """
        if username in self.users:
            raise ValueError(f"User '{username}' is already registered for 2FA.")

        secret = self.generate_secret()
        provisioning_uri = self.get_provisioning_uri(username, secret)

        # Store user data
        self.users[username] = {
            "secret": secret,
            "email": email,
            "enabled": True,
            "created_at": time.time(),
            "verified": False,  # User must verify with a valid code first
            "backup_codes": self._generate_backup_codes(),
        }
        self._save_users()

        # Generate QR code
        qr_filepath = f"qr_{username}.png"
        self.generate_qr_code(username, secret, filepath=qr_filepath)

        return {
            "username": username,
            "secret": secret,
            "provisioning_uri": provisioning_uri,
            "qr_code_path": qr_filepath,
            "backup_codes": self.users[username]["backup_codes"],
        }

    def _generate_backup_codes(self, count=8, length=8):
        """Generate one-time backup codes."""
        codes = []
        for _ in range(count):
            code = base64.b32encode(os.urandom(length)).decode("utf-8")[:length]
            codes.append(code.lower())
        return codes

    def verify_user_setup(self, username, code):
        """
        Verify initial TOTP setup by requiring user to enter a valid code.
        This confirms they've properly set up their authenticator app.
        """
        if username not in self.users:
            raise ValueError(f"User '{username}' is not registered for 2FA.")

        user = self.users[username]
        if self.verify_totp(user["secret"], code):
            user["verified"] = True
            self._save_users()
            return True
        return False

    def authenticate(self, username, code):
        """
        Authenticate a user with their TOTP code.

        Args:
            username: The username
            code: The TOTP code or backup code

        Returns:
            dict with authentication result and details
        """
        if username not in self.users:
            return {"success": False, "error": "User not registered for 2FA"}

        user = self.users[username]

        if not user["enabled"]:
            return {"success": False, "error": "2FA is disabled for this user"}

        if not user["verified"]:
            return {"success": False, "error": "2FA setup not verified. Please complete setup first."}

        # Check if it's a backup code
        code_str = str(code).strip().lower()
        if code_str in user.get("backup_codes", []):
            user["backup_codes"].remove(code_str)
            self._save_users()
            return {
                "success": True,
                "method": "backup_code",
                "remaining_backup_codes": len(user["backup_codes"]),
            }

        # Verify TOTP code
        if self.verify_totp(user["secret"], code):
            return {"success": True, "method": "totp"}

        return {"success": False, "error": "Invalid TOTP code"}

    def disable_2fa(self, username):
        """Disable 2FA for a user."""
        if username not in self.users:
            raise ValueError(f"User '{username}' is not registered for 2FA.")

        self.users[username]["enabled"] = False
        self._save_users()
        print(f"2FA disabled for user '{username}'.")

    def enable_2fa(self, username):
        """Re-enable 2FA for a user."""
        if username not in self.users:
            raise ValueError(f"User '{username}' is not registered for 2FA.")

        self.users[username]["enabled"] = True
        self._save_users()
        print(f"2FA enabled for user '{username}'.")

    def regenerate_backup_codes(self, username):
        """Regenerate backup codes for a user."""
        if username not in self.users:
            raise ValueError(f"User '{username}' is not registered for 2FA.")

        new_codes = self._generate_backup_codes()
        self.users[username]["backup_codes"] = new_codes
        self._save_users()
        return new_codes

    def get_user_info(self, username):
        """Get user 2FA information (excluding secret)."""
        if username not in self.users:
            return None

        user = self.users[username]
        return {
            "username": username,
            "email": user.get("email"),
            "enabled": user["enabled"],
            "verified": user["verified"],
            "created_at": user["created_at"],
            "remaining_backup_codes": len(user.get("backup_codes", [])),
        }

    def remove_user(self, username):
        """Remove a user from the 2FA system."""
        if username in self.users:
            del self.users[username]
            self._save_users()
            print(f"User '{username}' removed from 2FA system.")
        else:
            raise ValueError(f"User '{username}' is not registered for 2FA.")


