def interactive_demo():
    """Run an interactive TOTP demo."""
    auth = TOTPAuthenticator(issuer="MFASystem")

    while True:
        print("\n" + "=" * 40)
        print("TOTP 2FA Management System")
        print("=" * 40)
        print("1. Register new user")
        print("2. Verify setup (enter TOTP code)")
        print("3. Authenticate user")
        print("4. Show current TOTP code")
        print("5. View user info")
        print("6. Regenerate backup codes")
        print("7. Enable/Disable 2FA")
        print("8. Remove user")
        print("9. Exit")
        print("-" * 40)

        choice = input("Select option: ").strip()

        try:
            if choice == "1":
                username = input("Enter username: ").strip()
                email = input("Enter email (optional): ").strip() or None
                result = auth.register_user(username, email)
                print(f"\nRegistration successful!")
                print(f"Secret: {result['secret']}")
                print(f"QR Code: {result['qr_code_path']}")
                print(f"Scan the QR code with your authenticator app.")
                print(f"\nBackup codes (save these securely):")
                for i, code in enumerate(result['backup_codes'], 1):
                    print(f"  {i}. {code}")

            elif choice == "2":
                username = input("Enter username: ").strip()
                code = input("Enter TOTP code from authenticator: ").strip()
                if auth.verify_user_setup(username, code):
                    print("Setup verified successfully! 2FA is now active.")
                else:
                    print("Invalid code. Please try again.")

            elif choice == "3":
                username = input("Enter username: ").strip()
                code = input("Enter TOTP code or backup code: ").strip()
                result = auth.authenticate(username, code)
                if result["success"]:
                    print(f"Authentication successful! Method: {result['method']}")
                    if result["method"] == "backup_code":
                        print(f"Remaining backup codes: {result['remaining_backup_codes']}")
                else:
                    print(f"Authentication failed: {result['error']}")

            elif choice == "4":
                username = input("Enter username: ").strip()
                if username in auth.users:
                    secret = auth.users[username]["secret"]
                    code = auth.generate_totp(secret)
                    remaining = auth.period - (int(time.time()) % auth.period)
                    print(f"Current TOTP: {code} (expires in {remaining}s)")
                else:
                    print("User not found.")

            elif choice == "5":
                username = input("Enter username: ").strip()
                info = auth.get_user_info(username)
                if info:
                    print(json.dumps(info, indent=2, default=str))
                else:
                    print("User not found.")

            elif choice == "6":
                username = input("Enter username: ").strip()
                codes = auth.regenerate_backup_codes(username)
                print("New backup codes:")
                for i, code in enumerate(codes, 1):
                    print(f"  {i}. {code}")

            elif choice == "7":
                username = input("Enter username: ").strip()
                action = input("Enable or disable? (e/d): ").strip().lower()
                if action == "e":
                    auth.enable_2fa(username)
                elif action == "d":
                    auth.disable_2fa(username)

            elif choice == "8":
                username = input("Enter username: ").strip()
                confirm = input(f"Remove 2FA for '{username}'? (yes/no): ").strip()
                if confirm.lower() == "yes":
                    auth.remove_user(username)

            elif choice == "9":
                print("Goodbye!")
                break

            else:
                print("Invalid option.")

        except ValueError as e:
            print(f"Error: {e}")
        except Exception as e:
            print(f"Unexpected error: {e}")


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "--interactive":
        interactive_demo()
    else:
        demo()